   207→func (c *Client) autoSync() {
   208→	if c.cfg.AutoSyncInterval == time.Duration(0) {
   209→		return
   210→	}
   211→
   212→	for {
   213→		select {
   214→		case <-c.ctx.Done():
   215→			return
   216→		case <-time.After(c.cfg.AutoSyncInterval):
   217→			ctx, cancel := context.WithTimeout(c.ctx, 5*time.Second)
   218→			err := c.Sync(ctx)
   219→			cancel()
   220→			if err != nil && !errors.Is(err, c.ctx.Err()) {
   221→				c.GetLogger().Info("Auto sync endpoints failed.", zap.Error(err))
   222→			}
   223→		}
   224→	}
   225→}
