   227→// dialSetupOpts gives the dial opts prior to any authentication.
   228→func (c *Client) dialSetupOpts(creds grpccredentials.TransportCredentials, dopts ...grpc.DialOption) []grpc.DialOption {
   229→	var opts []grpc.DialOption
   230→
   231→	if c.cfg.DialKeepAliveTime > 0 {
   232→		params := keepalive.ClientParameters{
   233→			Time:                c.cfg.DialKeepAliveTime,
   234→			Timeout:             c.cfg.DialKeepAliveTimeout,
   235→			PermitWithoutStream: c.cfg.PermitWithoutStream,
   236→		}
   237→		opts = append(opts, grpc.WithKeepaliveParams(params))
   238→	}
   239→	opts = append(opts, dopts...)
   240→
   241→	if creds != nil {
   242→		opts = append(opts, grpc.WithTransportCredentials(creds))
   243→	} else {
   244→		opts = append(opts, grpc.WithTransportCredentials(insecure.NewCredentials()))
   245→	}
   246→
   247→	unaryMaxRetries := defaultUnaryMaxRetries
   248→	if c.cfg.MaxUnaryRetries > 0 {
   249→		unaryMaxRetries = c.cfg.MaxUnaryRetries
   250→	}
   251→
   252→	backoffWaitBetween := defaultBackoffWaitBetween
   253→	if c.cfg.BackoffWaitBetween > 0 {
   254→		backoffWaitBetween = c.cfg.BackoffWaitBetween
   255→	}
   256→
   257→	backoffJitterFraction := defaultBackoffJitterFraction
   258→	if c.cfg.BackoffJitterFraction > 0 {
   259→		backoffJitterFraction = c.cfg.BackoffJitterFraction
   260→	}
   261→
   262→	// Interceptor retry and backoff.
   263→	// TODO: Replace all of clientv3/retry.go with RetryPolicy:
   264→	// https://github.com/grpc/grpc-proto/blob/cdd9ed5c3d3f87aef62f373b93361cf7bddc620d/grpc/service_config/service_config.proto#L130
   265→	rrBackoff := withBackoff(c.roundRobinQuorumBackoff(backoffWaitBetween, backoffJitterFraction))
   266→	opts = append(opts,
   267→		// Disable stream retry by default since go-grpc-middleware/retry does not support client streams.
   268→		// Streams that are safe to retry are enabled individually.
   269→		grpc.WithStreamInterceptor(c.streamClientInterceptor(withMax(0), rrBackoff)),
   270→		grpc.WithUnaryInterceptor(c.unaryClientInterceptor(withMax(unaryMaxRetries), rrBackoff)),
   271→	)
   272→
   273→	return opts
   274→}
