   285→func (c *Client) getToken(ctx context.Context) error {
   286→	var err error // return last error in a case of fail
   287→
   288→	if c.Token != "" {
   289→		c.authTokenBundle.UpdateAuthToken(c.Token)
   290→		return nil
   291→	}
   292→
   293→	if c.Username == "" || c.Password == "" {
   294→		return nil
   295→	}
