   309→// dialWithBalancer dials the client's current load balanced resolver group.  The scheme of the host
   310→// of the provided endpoint determines the scheme used for all endpoints of the client connection.
   311→func (c *Client) dialWithBalancer(dopts ...grpc.DialOption) (*grpc.ClientConn, error) {
   312→	creds := c.credentialsForEndpoint(c.Endpoints()[0])
   313→	opts := append(dopts, grpc.WithResolvers(c.resolver))
   314→	return c.dial(creds, opts...)
