   341→func authority(endpoint string) string {
   342→	spl := strings.SplitN(endpoint, "://", 2)
   343→	if len(spl) < 2 {
   344→		if strings.HasPrefix(endpoint, "unix:") {
   345→			return endpoint[len("unix:"):]
   346→		}
   347→		if strings.HasPrefix(endpoint, "unixs:") {
   348→			return endpoint[len("unixs:"):]
   349→		}
   350→		return endpoint
   351→	}
   352→	return spl[1]
   353→}
