   372→func newClient(cfg *Config) (*Client, error) {
   373→	if cfg == nil {
   374→		cfg = &Config{}
   375→	}
   376→	var creds grpccredentials.TransportCredentials
   377→	if cfg.TLS != nil {
   378→		creds = credentials.NewTransportCredential(cfg.TLS)
   379→	}
   380→
   381→	if cfg.Token != "" && (cfg.Username != "" || cfg.Password != "") {
   382→		return nil, ErrMutuallyExclusiveCfg
   383→	}
   384→
   385→	// use a temporary skeleton client to bootstrap first connection
   386→	baseCtx := context.TODO()
   387→	if cfg.Context != nil {
   388→		baseCtx = cfg.Context
   389→	}
   390→
   391→	ctx, cancel := context.WithCancel(baseCtx)
   392→	client := &Client{
   393→		conn:     nil,
   394→		cfg:      *cfg,
   395→		creds:    creds,
   396→		ctx:      ctx,
   397→		cancel:   cancel,
   398→		epMu:     new(sync.RWMutex),
   399→		callOpts: defaultCallOpts,
   400→	}
   401→
   402→	var err error
   403→	var lg *zap.Logger
   404→	if cfg.Logger != nil {
   405→		lg = cfg.Logger
   406→	} else if cfg.LogConfig != nil {
   407→		lg, err = cfg.LogConfig.Build()
   408→	} else {
   409→		lg, err = logutil.CreateDefaultZapLogger(ClientLogLevel())
   410→		if lg != nil {
   411→			lg = lg.Named("etcd-client")
   412→		}
   413→	}
   414→	if err != nil {
   415→		return nil, err
   416→	}
   417→	client.lg.Store(lg)
   418→
   419→	if cfg.Username != "" && cfg.Password != "" {
   420→		client.Username = cfg.Username
   421→		client.Password = cfg.Password
   422→		client.authTokenBundle = credentials.NewPerRPCCredentialBundle()
   423→	}
   424→
   425→	if cfg.Token != "" {
   426→		client.Token = cfg.Token
   427→		client.authTokenBundle = credentials.NewPerRPCCredentialBundle()
   428→	}
   429→
   430→	if cfg.MaxCallSendMsgSize > 0 || cfg.MaxCallRecvMsgSize > 0 {
   431→		if cfg.MaxCallRecvMsgSize > 0 && cfg.MaxCallSendMsgSize > cfg.MaxCallRecvMsgSize {
   432→			return nil, fmt.Errorf("gRPC message recv limit (%d bytes) must be greater than send limit (%d bytes)", cfg.MaxCallRecvMsgSize, cfg.MaxCallSendMsgSize)
   433→		}
   434→		callOpts := []grpc.CallOption{
   435→			defaultWaitForReady,
   436→			defaultMaxCallSendMsgSize,
   437→			defaultMaxCallRecvMsgSize,
   438→		}
   439→		if cfg.MaxCallSendMsgSize > 0 {
   440→			callOpts[1] = grpc.MaxCallSendMsgSize(cfg.MaxCallSendMsgSize)
   441→		}
   442→		if cfg.MaxCallRecvMsgSize > 0 {
   443→			callOpts[2] = grpc.MaxCallRecvMsgSize(cfg.MaxCallRecvMsgSize)
   444→		}
   445→		client.callOpts = callOpts
   446→	}
   447→
   448→	client.resolver = resolver.New(cfg.Endpoints...)
   449→
   450→	if len(cfg.Endpoints) < 1 {
   451→		client.cancel()
   452→		return nil, errors.New("at least one Endpoint is required in client config")
   453→	}
   454→	client.Compat_SetEndpoints(cfg.Endpoints...)
   455→
   456→	// Use a provided endpoint target so that for https:// without any tls config given, then
   457→	// grpc will assume the certificate server name is the endpoint host.
   458→	conn, err := client.dialWithBalancer()
   459→	if err != nil {
   460→		client.cancel()
   461→		client.resolver.Close()
   462→		// TODO: Error like `fmt.Errorf(dialing [%s] failed: %v, strings.Join(cfg.Endpoints, ";"), err)` would help with debugging a lot.
   463→		return nil, err
   464→	}
   465→	client.conn = conn
   466→
   467→	client.Cluster = NewCluster(client)
   468→	client.KV = NewKV(client)
   469→	client.Lease = NewLease(client)
   470→	client.Watcher = NewWatcher(client)
   471→	client.Auth = NewAuth(client)
   472→	client.Maintenance = NewMaintenance(client)
   473→
   474→	// get token with established connection
   475→	ctx, cancel = client.ctx, func() {}
   476→	if client.cfg.DialTimeout > 0 {
   477→		ctx, cancel = context.WithTimeout(ctx, client.cfg.DialTimeout)
   478→	}
   479→	err = client.getToken(ctx)
   480→	if err != nil {
   481→		client.Close()
   482→		cancel()
   483→		// TODO: Consider fmt.Errorf("communicating with [%s] failed: %v", strings.Join(cfg.Endpoints, ";"), err)
   484→		return nil, err
   485→	}
   486→	cancel()
   487→
   488→	if cfg.RejectOldCluster {
   489→		if err := client.checkVersion(); err != nil {
   490→			client.Close()
   491→			return nil, err
   492→		}
   493→	}
   494→
   495→	go client.autoSync()
   496→	return client, nil
   497→}
