   515→// minSupportedVersion returns the minimum version supported, which is the previous minor release.
   516→func minSupportedVersion() *semver.Version {
   517→	ver := semver.Must(semver.NewVersion(version.Version))
   518→	// consider only major and minor version
   519→	ver = &semver.Version{Major: ver.Major, Minor: ver.Minor}
   520→	for i := range version.AllVersions {
   521→		if version.AllVersions[i].Equal(*ver) {
   522→			if i == 0 {
   523→				return ver
   524→			}
   525→			return &version.AllVersions[i-1]
   526→		}
   527→	}
   528→	panic("current version is not in the version list")
   529→}
