   531→func (c *Client) checkVersion() (err error) {
   532→	var wg sync.WaitGroup
   533→
   534→	eps := c.Endpoints()
   535→	errc := make(chan error, len(eps))
   536→	ctx, cancel := context.WithCancel(c.ctx)
   537→	if c.cfg.DialTimeout > 0 {
   538→		cancel()
   539→		ctx, cancel = context.WithTimeout(c.ctx, c.cfg.DialTimeout)
   540→	}
   541→
   542→	wg.Add(len(eps))
   543→	for _, ep := range eps {
   544→		// if cluster is current, any endpoint gives a recent version
   545→		go func(e string) {
   546→			defer wg.Done()
   547→			resp, rerr := c.Status(ctx, e)
   548→			if rerr != nil {
   549→				errc <- rerr
   550→				return
   551→			}
   552→			vs, serr := semver.NewVersion(resp.Version)
   553→			if serr != nil {
   554→				errc <- serr
   555→				return
   556→			}
   557→
   558→			if vs.LessThan(*minSupportedVersion()) {
   559→				rerr = ErrOldCluster
   560→			}
   561→			errc <- rerr
   562→		}(ep)
   563→	}
   564→	// wait for success
   565→	for range eps {
   566→		if err = <-errc; err != nil {
   567→			break
   568→		}
   569→	}
   570→	cancel()
   571→	wg.Wait()
   572→	return err
   573→}
